[{"location":"design/design/#Architecture-Design","page":"Architecture Design","title":"Architecture Design","text":"","category":"section"},{"location":"design/design/#System-Overview","page":"Architecture Design","title":"System Overview","text":"","category":"section"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"The EnvironmentEngine implements a mediator pattern architecture for time-based task scheduling. The system maintains a single source of truth for time through a centralized clock, with a scheduler distributing time deltas to individual tasks.","category":"page"},{"location":"design/design/#Architectural-Components","page":"Architecture Design","title":"Architectural Components","text":"","category":"section"},{"location":"design/design/#Clock-Interface","page":"Architecture Design","title":"Clock Interface","text":"","category":"section"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"Abstract time provider that exposes a now() method. Implementations include:","category":"page"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"Real-time clock for production systems\nVirtual clock for simulation and testing","category":"page"},{"location":"design/design/#Task-Interface","page":"Architecture Design","title":"Task Interface","text":"","category":"section"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"Executable units implementing an execute method. Tasks can access states of objects they describe.","category":"page"},{"location":"design/design/#TaskScheduler","page":"Architecture Design","title":"TaskScheduler","text":"","category":"section"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"Central mediator that:","category":"page"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"Maintains scheduled task registry\nPolls clock for elapsed time\nDistributes time deltas to registered tasks\nManages task lifecycle (enable/disable/unschedule)","category":"page"},{"location":"design/design/#ScheduledTask","page":"Architecture Design","title":"ScheduledTask","text":"","category":"section"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"Internal data structure containing:","category":"page"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"Task reference\nExecution period\nTime accumulator\nEnabled state","category":"page"},{"location":"design/design/#Execution-Model","page":"Architecture Design","title":"Execution Model","text":"","category":"section"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"Initialization: Clock and scheduler instantiated, tasks registered with execution periods\nRuntime: Scheduler polls clock, calculates time delta, forwards delta to all registered tasks\nTask Execution: Tasks receive time delta from scheduler, update internal accumulators, execute when thresholds met","category":"page"},{"location":"design/design/#Design-Patterns","page":"Architecture Design","title":"Design Patterns","text":"","category":"section"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"Mediator: TaskScheduler coordinates between Clock and Tasks\nStrategy: Multiple Clock implementations provide different time sources\nTemplate Method: Task interface defines execution contract","category":"page"},{"location":"design/design/#Dependencies","page":"Architecture Design","title":"Dependencies","text":"","category":"section"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"Clock implementations depend on Clock interface\nTask implementations depend on Task interface  \nTaskScheduler depends on Clock interface and Task interface\nNo circular dependencies between components","category":"page"},{"location":"design/design/#Performance-Characteristics","page":"Architecture Design","title":"Performance Characteristics","text":"","category":"section"},{"location":"design/design/","page":"Architecture Design","title":"Architecture Design","text":"O(n) execution complexity where n is number of scheduled tasks\nConstant memory overhead per scheduled task\nNo dynamic allocation during execution loop","category":"page"},{"location":"api_spec/farama/#Farama-(standard-RL-environment)","page":"Farama Gym Environment","title":"Farama (standard RL environment)","text":"","category":"section"},{"location":"api_spec/farama/","page":"Farama Gym Environment","title":"Farama Gym Environment","text":"For farama environments, we do not need a clock.","category":"page"},{"location":"api_spec/farama/","page":"Farama Gym Environment","title":"Farama Gym Environment","text":"using EnvironmentEngine\n\nenv = Environment()\nagent = Agent()\n\nobs_cache = CircularBuffer{ConcreteObservationType}(1)\naction_cache = CircularBuffer{ConcreteActionType}(1)\n\nevery(obs_cache) do obs\n    push!(action_cache, action_inference(agent, obs))\nend\n\nevery(action_cache) do action\n    obs = step!(env, action)\n    push!(obs_cache, obs)\nend\n\n\n\n","category":"page"},{"location":"design/api/#API-Design","page":"API Design","title":"API Design","text":"","category":"section"},{"location":"design/api/#Overview","page":"API Design","title":"Overview","text":"","category":"section"},{"location":"design/api/","page":"API Design","title":"API Design","text":"The EnvironmentEngine provides a high-level API centered around the every function, which creates and schedules tasks through multiple dispatch based on the input type. This design enables intuitive task creation while maintaining the underlying architectural separation.","category":"page"},{"location":"design/api/#Core-API","page":"API Design","title":"Core API","text":"","category":"section"},{"location":"design/api/#Task-Creation","page":"API Design","title":"Task Creation","text":"","category":"section"},{"location":"design/api/#Time-Based-Tasks","page":"API Design","title":"Time-Based Tasks","text":"","category":"section"},{"location":"design/api/","page":"API Design","title":"API Design","text":"# Execute every 2 milliseconds\nevery(2ms) do dt\n    act!(agent, env)\nend\n\n# Execute every 100 microseconds\nevery(100μs) do dt\n    update_sensors!()\nend","category":"page"},{"location":"design/api/#Event-Based-Tasks","page":"API Design","title":"Event-Based Tasks","text":"","category":"section"},{"location":"design/api/","page":"API Design","title":"API Design","text":"# Execute when observation cache changes\nevery(obs_cache) do obs\n    state_update!(agent, obs)\nend\n\n# Execute when action cache updates\nevery(action_cache) do action\n    execute_action!(robot, action)\nend","category":"page"},{"location":"design/api/#Multiple-Dispatch","page":"API Design","title":"Multiple Dispatch","text":"","category":"section"},{"location":"design/api/","page":"API Design","title":"API Design","text":"The every function automatically creates the appropriate task type:","category":"page"},{"location":"design/api/","page":"API Design","title":"API Design","text":"every(time_period) → Creates TimedTask\nevery(observable_object) → Creates EventTask","category":"page"},{"location":"design/api/","page":"API Design","title":"API Design","text":"Julia's type system routes to the correct constructor based on the first argument.","category":"page"},{"location":"design/api/#Global-Scheduler","page":"API Design","title":"Global Scheduler","text":"","category":"section"},{"location":"design/api/","page":"API Design","title":"API Design","text":"The system provides a global scheduler instance for convenience:","category":"page"},{"location":"design/api/","page":"API Design","title":"API Design","text":"# Package automatically creates default scheduler with default clock\n# Tasks created with every() are automatically registered\n\n# Can configure or replace the global scheduler\nset_global_scheduler!(custom_scheduler)\nset_global_clock!(VirtualClock())","category":"page"},{"location":"design/api/#Task-Control","page":"API Design","title":"Task Control","text":"","category":"section"},{"location":"design/api/#Enable/Disable","page":"API Design","title":"Enable/Disable","text":"","category":"section"},{"location":"design/api/","page":"API Design","title":"API Design","text":"# Disable a specific task\ndisable_task!(task_handle)\n\n# Re-enable a task\nenable_task!(task_handle)","category":"page"},{"location":"design/api/#Task-Removal","page":"API Design","title":"Task Removal","text":"","category":"section"},{"location":"design/api/","page":"API Design","title":"API Design","text":"# Remove a task from the system\nremove_task!(task_handle)","category":"page"},{"location":"design/api/#Clock-Control","page":"API Design","title":"Clock Control","text":"","category":"section"},{"location":"design/api/#Virtual-Clock-Operations","page":"API Design","title":"Virtual Clock Operations","text":"","category":"section"},{"location":"design/api/","page":"API Design","title":"API Design","text":"# Advance time by 1ms\nadvance_time!(1ms)\n\n# Set time to specific value\nset_time!(5.0s)\n\n# Reset to zero\nreset_time!()","category":"page"},{"location":"design/api/#Configuration","page":"API Design","title":"Configuration","text":"","category":"section"},{"location":"design/api/#Scheduler-Settings","page":"API Design","title":"Scheduler Settings","text":"","category":"section"},{"location":"design/api/","page":"API Design","title":"API Design","text":"# Configure execution frequency\nset_scheduler_frequency!(1000Hz)\n\n# Set time step for virtual clock\nset_time_step!(1ms)","category":"page"},{"location":"design/api/#Clock-Selection","page":"API Design","title":"Clock Selection","text":"","category":"section"},{"location":"design/api/","page":"API Design","title":"API Design","text":"# Switch to virtual clock for simulation\nuse_virtual_clock!()\n\n# Switch back to real-time clock\nuse_machine_clock!()","category":"page"},{"location":"design/scheduler/#Scheduler-Design","page":"Scheduler Design","title":"Scheduler Design","text":"","category":"section"},{"location":"design/scheduler/#Overview","page":"Scheduler Design","title":"Overview","text":"","category":"section"},{"location":"design/scheduler/","page":"Scheduler Design","title":"Scheduler Design","text":"The Scheduler implements the mediator pattern, serving as the central coordinator between the clock system and individual tasks. It maintains a single source of truth for time distribution while keeping tasks decoupled from each other and from timekeeping logic.","category":"page"},{"location":"design/scheduler/#Core-Responsibilities","page":"Scheduler Design","title":"Core Responsibilities","text":"","category":"section"},{"location":"design/scheduler/#Time-Management","page":"Scheduler Design","title":"Time Management","text":"","category":"section"},{"location":"design/scheduler/","page":"Scheduler Design","title":"Scheduler Design","text":"Polls the clock for elapsed time\nCalculates time deltas between execution cycles\nDistributes time deltas to all registered tasks","category":"page"},{"location":"design/scheduler/#Task-Registry","page":"Scheduler Design","title":"Task Registry","text":"","category":"section"},{"location":"design/scheduler/","page":"Scheduler Design","title":"Scheduler Design","text":"Maintains collection of scheduled tasks\nHandles task registration and deregistration\nManages task lifecycle (enable/disable)","category":"page"},{"location":"design/scheduler/#Execution-Coordination","page":"Scheduler Design","title":"Execution Coordination","text":"","category":"section"},{"location":"design/scheduler/","page":"Scheduler Design","title":"Scheduler Design","text":"Calls execute(dt) on all registered tasks\nProvides consistent time progression to all tasks\nMaintains execution order and consistency","category":"page"},{"location":"design/scheduler/#Execution-Model","page":"Scheduler Design","title":"Execution Model","text":"","category":"section"},{"location":"design/scheduler/#Main-Execution-Loop","page":"Scheduler Design","title":"Main Execution Loop","text":"","category":"section"},{"location":"design/scheduler/","page":"Scheduler Design","title":"Scheduler Design","text":"The scheduler polls the clock, calculates time deltas, and distributes them to all registered tasks.","category":"page"},{"location":"design/scheduler/#Time-Distribution","page":"Scheduler Design","title":"Time Distribution","text":"","category":"section"},{"location":"design/scheduler/","page":"Scheduler Design","title":"Scheduler Design","text":"Scheduler receives time delta from clock\nAll tasks receive the same time delta on each cycle\nTasks internally decide whether to execute based on their trigger logic\nNo task execution affects timing of other tasks","category":"page"},{"location":"design/scheduler/#Task-Management","page":"Scheduler Design","title":"Task Management","text":"","category":"section"},{"location":"design/scheduler/#Registration","page":"Scheduler Design","title":"Registration","text":"","category":"section"},{"location":"design/scheduler/","page":"Scheduler Design","title":"Scheduler Design","text":"Tasks are registered with the scheduler and stored in an internal collection.","category":"page"},{"location":"design/scheduler/#Lifecycle-Operations","page":"Scheduler Design","title":"Lifecycle Operations","text":"","category":"section"},{"location":"design/scheduler/","page":"Scheduler Design","title":"Scheduler Design","text":"Enable/Disable: Tasks can be temporarily disabled without removal\nUnschedule: Complete removal of tasks from the system\nReset: Clear all task state and timing accumulators","category":"page"},{"location":"design/scheduler/#Internal-Data-Structures","page":"Scheduler Design","title":"Internal Data Structures","text":"","category":"section"},{"location":"design/scheduler/","page":"Scheduler Design","title":"Scheduler Design","text":"The scheduler maintains internal structures to track registered tasks and their state.","category":"page"},{"location":"design/scheduler/#Global-Scheduler-Instance","page":"Scheduler Design","title":"Global Scheduler Instance","text":"","category":"section"},{"location":"design/scheduler/","page":"Scheduler Design","title":"Scheduler Design","text":"The system provides a global scheduler instance for convenience:","category":"page"},{"location":"design/scheduler/","page":"Scheduler Design","title":"Scheduler Design","text":"Automatically created when package loads\nUses default clock implementation\nCan be configured or replaced at runtime\nProvides the every() function interface","category":"page"},{"location":"api_spec/drone/#Drone-example","page":"Drone Environment","title":"Drone example","text":"","category":"section"},{"location":"api_spec/drone/","page":"Drone Environment","title":"Drone Environment","text":"The simplest example that uses the environment engine is a single agent that interacts with an environment with an associated clock.","category":"page"},{"location":"api_spec/drone/","page":"Drone Environment","title":"Drone Environment","text":"using EnvironmentEngine\n\ninitialize_clock!(real_time_factor=1.0)\n\nenv = Environment()\nagent = Agent()\n\nobs_cache = CircularBuffer{ConcreteObservationType}(10)\n\n# Sensor frequency\nevery(1ms) do dt\n    push!(obs_cache, generate_observation(env, agent))\nend\n\n# State update as soon as observation is available\nevery(obs_cache) do obs\n    state_update!(agent, obs)\nend\n\n# Planning as soon as state is possible\nevery(asap) do \n    plan!(agent)\nend\n\n# Action execution on hardware limitation frequency\nevery(2ms) do dt\n    act!(agent, env)\nend\n\n# Environment update on seperate frequency (e.g. physics engine)\nevery(1ms) do dt\n    update!(env, dt)\nend\n","category":"page"},{"location":"api_spec/multi_agent/#Multi-agent-environment","page":"Multi-Agent Environment","title":"Multi-agent environment","text":"","category":"section"},{"location":"api_spec/multi_agent/","page":"Multi-Agent Environment","title":"Multi-Agent Environment","text":"using EnvironmentEngine\n\ninitialize_clock!(real_time_factor=1.0)\n\nenv = Environment()\n\nfunction add!(agent)\n    \n    obs_cache = CircularBuffer{ConcreteObservationType}(10)\n\n    # Sensor frequency\n    every(1ms) do\n        push!(obs_cache, generate_observation(env, agent))\n    end\n\n    # State update as soon as observation is available\n    every(obs_cache) do obs\n        state_update!(agent, obs)\n    end\n\n    # Planning as soon as state is possible\n    every(asap) do \n        plan!(agent)\n    end\n\n    # Action execution on hardware limitation frequency\n    every(2ms) do \n        act!(agent, env)\n    end\nend\n\nadd!(Agent())\nadd!(Agent())\n\nevery(1ms) do dt\n    update!(env, dt)\nend\n","category":"page"},{"location":"design/tasks/#Task-System-Design","page":"Task System","title":"Task System Design","text":"","category":"section"},{"location":"design/tasks/#Task-Interface","page":"Task System","title":"Task Interface","text":"","category":"section"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"All tasks implement a common interface regardless of their trigger mechanism:","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"abstract type Task end\n\nfunction execute(task::Task, dt::Quantity{<:Number, 𝐓})\n    # Must be implemented by concrete task types\nend","category":"page"},{"location":"design/tasks/#Task-Types","page":"Task System","title":"Task Types","text":"","category":"section"},{"location":"design/tasks/#TimedTask","page":"Task System","title":"TimedTask","text":"","category":"section"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Tasks that execute at regular time intervals.","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Behavior:","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Maintains internal time accumulator\nReceives time delta from scheduler on each execution cycle\nExecutes when accumulator reaches execution period threshold\nResets accumulator after execution","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Example:","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"every(2ms) do dt\n    act!(agent, env)\nend","category":"page"},{"location":"design/tasks/#EventTask","page":"Task System","title":"EventTask","text":"","category":"section"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Tasks that execute when specific conditions are met.","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Behavior:","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Stores hash of observed object state\nCompares current hash with stored hash on each execution cycle\nExecutes when hash changes (indicating state change)\nUpdates stored hash after execution","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Example:","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"every(obs_cache) do obs\n    state_update!(agent, obs)\nend","category":"page"},{"location":"design/tasks/#Task-Creation","page":"Task System","title":"Task Creation","text":"","category":"section"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"The every function provides a unified interface for creating both task types:","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Time-based: every(time_period) do dt ... end\nEvent-based: every(observable_object) do obj ... end","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Julia's multiple dispatch automatically routes to the appropriate task constructor based on the first argument type.","category":"page"},{"location":"design/tasks/#Task-State-Management","page":"Task System","title":"Task State Management","text":"","category":"section"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Tasks are stateless in terms of execution logic but may maintain:","category":"page"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Timing accumulators (TimedTask)\nState hashes (EventTask)\nExecution periods\nEnabled/disabled state","category":"page"},{"location":"design/tasks/#Task-Execution-Model","page":"Task System","title":"Task Execution Model","text":"","category":"section"},{"location":"design/tasks/","page":"Task System","title":"Task System","text":"Registration: Task registers with global scheduler\nExecution Cycle: Scheduler calls execute(dt) on all registered tasks\nSelf-Determination: Each task decides whether to perform work based on its internal logic\nState Update: Task updates internal state after execution","category":"page"},{"location":"#EnvironmentEngine","page":"Home","title":"EnvironmentEngine","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Documentation for EnvironmentEngine.","category":"page"},{"location":"","page":"Home","title":"Home","text":"","category":"page"},{"location":"#EnvironmentEngine.execute-Tuple{EnvironmentEngine.ScheduledTask, Unitful.Quantity{<:Number, 𝐓}}","page":"Home","title":"EnvironmentEngine.execute","text":"execute(task::Task, dt::Quantity{<:Number, 𝐓})\n\nExecute the task with the given time delta. The task decides internally whether to perform work.\n\n\n\n\n\n","category":"method"},{"location":"#EnvironmentEngine.get_clock-Tuple{EnvironmentEngine.Scheduler}","page":"Home","title":"EnvironmentEngine.get_clock","text":"get_clock(scheduler::Scheduler)\n\nGet the clock associated with the scheduler.\n\n\n\n\n\n","category":"method"},{"location":"#EnvironmentEngine.now-Tuple{EnvironmentEngine.Clock}","page":"Home","title":"EnvironmentEngine.now","text":"now(clock::Clock)\n\nReturns the current time in the clock using Unitful to represent the unit of time.\n\n\n\n\n\n","category":"method"},{"location":"#EnvironmentEngine.run!-Tuple{EnvironmentEngine.Scheduler}","page":"Home","title":"EnvironmentEngine.run!","text":"run!(scheduler::Scheduler)\n\nExecute one cycle of the scheduler, distributing time to all registered tasks.\n\n\n\n\n\n","category":"method"},{"location":"#EnvironmentEngine.schedule!-Tuple{EnvironmentEngine.Scheduler, Task}","page":"Home","title":"EnvironmentEngine.schedule!","text":"schedule!(scheduler::Scheduler, task::Task)\n\nRegister a task with the scheduler to run at the specified period.\n\n\n\n\n\n","category":"method"},{"location":"design/architecture/#Architecture-Overview","page":"Architecture Overview","title":"Architecture Overview","text":"","category":"section"},{"location":"design/architecture/#System-Design","page":"Architecture Overview","title":"System Design","text":"","category":"section"},{"location":"design/architecture/","page":"Architecture Overview","title":"Architecture Overview","text":"The EnvironmentEngine implements a mediator pattern architecture for time-based task scheduling. The system maintains a single source of truth for time through a centralized clock, with a scheduler distributing time deltas to individual tasks.","category":"page"},{"location":"design/architecture/#Core-Principles","page":"Architecture Overview","title":"Core Principles","text":"","category":"section"},{"location":"design/architecture/","page":"Architecture Overview","title":"Architecture Overview","text":"Single time source: Centralized clock provides authoritative time progression\nMediator pattern: TaskScheduler coordinates between clock and tasks\nUnified execution model: All tasks implement the same interface regardless of trigger type\nSeparation of concerns: Timekeeping, task execution, and coordination are cleanly separated","category":"page"},{"location":"design/architecture/#High-Level-Components","page":"Architecture Overview","title":"High-Level Components","text":"","category":"section"},{"location":"design/architecture/#Clock-Interface","page":"Architecture Overview","title":"Clock Interface","text":"","category":"section"},{"location":"design/architecture/","page":"Architecture Overview","title":"Architecture Overview","text":"Abstract time provider that exposes a now() method. Multiple implementations allow for different time sources:","category":"page"},{"location":"design/architecture/","page":"Architecture Overview","title":"Architecture Overview","text":"Real-time clock for production systems\nVirtual clock for simulation and testing","category":"page"},{"location":"design/architecture/#Task-Interface","page":"Architecture Overview","title":"Task Interface","text":"","category":"section"},{"location":"design/architecture/","page":"Architecture Overview","title":"Architecture Overview","text":"Executable units implementing an execute method. Tasks can access states of objects they describe.","category":"page"},{"location":"design/architecture/#TaskScheduler","page":"Architecture Overview","title":"TaskScheduler","text":"","category":"section"},{"location":"design/architecture/","page":"Architecture Overview","title":"Architecture Overview","text":"Central mediator that:","category":"page"},{"location":"design/architecture/","page":"Architecture Overview","title":"Architecture Overview","text":"Maintains scheduled task registry\nPolls clock for elapsed time\nDistributes time deltas to registered tasks\nManages task lifecycle (enable/disable/unschedule)","category":"page"},{"location":"design/architecture/#Design-Patterns","page":"Architecture Overview","title":"Design Patterns","text":"","category":"section"},{"location":"design/architecture/","page":"Architecture Overview","title":"Architecture Overview","text":"Mediator: TaskScheduler coordinates between Clock and Tasks\nStrategy: Multiple Clock implementations provide different time sources\nTemplate Method: Task interface defines execution contract","category":"page"},{"location":"design/architecture/#Dependencies","page":"Architecture Overview","title":"Dependencies","text":"","category":"section"},{"location":"design/architecture/","page":"Architecture Overview","title":"Architecture Overview","text":"Clock implementations depend on Clock interface\nTask implementations depend on Task interface  \nTaskScheduler depends on Clock interface and Task interface\nNo circular dependencies between components","category":"page"},{"location":"design/architecture/#Performance-Characteristics","page":"Architecture Overview","title":"Performance Characteristics","text":"","category":"section"},{"location":"design/architecture/","page":"Architecture Overview","title":"Architecture Overview","text":"O(n) execution complexity where n is number of scheduled tasks\nConstant memory overhead per scheduled task\nNo dynamic allocation during execution loop","category":"page"},{"location":"design/clocks/#Clock-System-Design","page":"Clock System","title":"Clock System Design","text":"","category":"section"},{"location":"design/clocks/#Overview","page":"Clock System","title":"Overview","text":"","category":"section"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"The clock system provides a unified interface for time measurement while supporting multiple implementations for different use cases. All clocks implement the same interface, allowing seamless switching between real-time and simulation modes.","category":"page"},{"location":"design/clocks/#Clock-Interface","page":"Clock System","title":"Clock Interface","text":"","category":"section"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"abstract type Clock end\n\nfunction now(clock::Clock)\n    # Returns current time as Quantity{<:Number, 𝐓}\n    # Must be implemented by concrete clock types\nend","category":"page"},{"location":"design/clocks/#Clock-Implementations","page":"Clock System","title":"Clock Implementations","text":"","category":"section"},{"location":"design/clocks/#MachineClock","page":"Clock System","title":"MachineClock","text":"","category":"section"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Real-time clock implementation for production systems.","category":"page"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Characteristics:","category":"page"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Uses system time as time source\nMonotonic time progression\nSuitable for real-time robotics applications\nTime cannot be controlled or manipulated","category":"page"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Implementation:","category":"page"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"struct MachineClock <: Clock end\n\nfunction now(clock::MachineClock)\n    return time()u\"s\"\nend","category":"page"},{"location":"design/clocks/#VirtualClock","page":"Clock System","title":"VirtualClock","text":"","category":"section"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Controllable clock implementation for simulation and testing.","category":"page"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Characteristics:","category":"page"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Manual time progression control\nDeterministic time behavior\nSuitable for simulation environments\nTime can be advanced, set, or reset","category":"page"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Core Methods:","category":"page"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"advance_time!(clock, dt): Increment clock by specified duration\nset_time!(clock, time): Set clock to specific time\nreset!(clock): Reset clock to zero","category":"page"},{"location":"design/clocks/#Time-Representation","page":"Clock System","title":"Time Representation","text":"","category":"section"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"All clocks use Unitful.jl for time representation:","category":"page"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Time values are Quantity{<:Number, 𝐓} types\nSupports all standard time units (s, ms, μs, etc.)\nType-safe time arithmetic and comparisons\nAutomatic unit conversion and validation","category":"page"},{"location":"design/clocks/#Clock-Configuration","page":"Clock System","title":"Clock Configuration","text":"","category":"section"},{"location":"design/clocks/#Default-Clock","page":"Clock System","title":"Default Clock","text":"","category":"section"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"System automatically creates default clock instance\nCan be configured or replaced at runtime\nScheduler uses configured clock for time queries","category":"page"},{"location":"design/clocks/#Clock-Switching","page":"Clock System","title":"Clock Switching","text":"","category":"section"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Scheduler can switch between clock implementations\nNo impact on registered tasks\nUseful for transitioning between real-time and simulation modes","category":"page"},{"location":"design/clocks/#Use-Cases","page":"Clock System","title":"Use Cases","text":"","category":"section"},{"location":"design/clocks/#Production-Systems","page":"Clock System","title":"Production Systems","text":"","category":"section"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Use MachineClock for real-time operation\nProvides accurate system time measurement\nSuitable for hardware control loops","category":"page"},{"location":"design/clocks/#Simulation-Environments","page":"Clock System","title":"Simulation Environments","text":"","category":"section"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Use VirtualClock for controlled time progression\nEnables deterministic simulation behavior\nUseful for testing and debugging","category":"page"},{"location":"design/clocks/#Testing","page":"Clock System","title":"Testing","text":"","category":"section"},{"location":"design/clocks/","page":"Clock System","title":"Clock System","text":"Inject VirtualClock for unit tests\nControl time progression for test scenarios\nEnsure reproducible test results","category":"page"}]
